async function dtLists(user, loa, findId) {
    let data1;
    const isGuest = user == process.env.Guest;
    const groupIds = isGuest
        ? []
        : (await prisma_1.prisma.dt_group_view.findMany({
            where: { user },
            select: { group_id: true }
        })).map(item => item.group_id);
    const visibleLoas = [0, ...groupIds];
    console.log(visibleLoas);
    const where = {
        shows: true,
        ...(findId ? { id: Number(findId) } : {})
    };
    if (loa == 1 && !isGuest) {
        where.OR = [
            {
                loa: {
                    in: visibleLoas
                }
            },
            {
                loa: 1,
                user
            }
        ];
    }
    else {
        where.loa = {
            in: visibleLoas
        };
    }
    data1 = await prisma_1.prisma.dt_find.findMany({
        where,
        orderBy: {
            date: 'desc'
        }
    });
    //查询该用户显示黑名单
    let userBlacList = (await prisma_1.prisma.dt_user_blacklist.findMany({
        where: {
            user,
            loa
        },
        select: {
            blocked_user: true
        }
    })).map(e => {
        return e.blocked_user;
    });
    let data = data1.map(a => {
        return {
            id: a.id,
            user: a.user,
            name: a.name,
            touxian: '',
            touxianUrl: a.user_img || undefined,
            text: a.text,
            imgShowAll: a.img_show_num,
            imgShowProportion: [],
            imgAllNum: a.img_all_num,
            videoShowAll: a.video_show_num,
            videoNum: a.video_num,
            date: (0, moment_1.default)(a.date).add(16, 'hours').format('YYYY-MM-DD HH:mm:ss'),
            idea: a.idea,
            po: a.pin_order,
            bgStyle: a.bg_style,
            longText: [],
            loa: a.loa,
            chatRoot: [],
        };
    }).filter(e => {
        //过滤掉黑名单中的用户
        return !userBlacList.includes(e.user);
    });
    for (let i = 0; i < data.length; i++) {
        //前缀为^AES^的内容且loa不为0或1的需要解密
        if (data[i].text.startsWith("^AES^")) {
            let key = process.env.miKey;
            data[i].text = mi.jie(data[i].text.slice(5), key);
        }
    }
    return data;
}
