//标签匹配度计算
async function bqbj(dtBq, word) {
    if (!dtBq) {
        return 0;
    }
    let numArr = [];
    for (let bd of dtBq) {
        let a = await bdbjs(bd.keyword, word);
        if (bd.isAi) {
            let num = Math.floor(a * 80);
            numArr.push(num);
        }
        if (!bd.isAi) {
            let num = Math.floor(a * 100);
            numArr.push(num);
        }
    }
    return Math.max(...numArr);
}
