async function getWord(word1, word2) {
    return new Promise((resolve, rejects) => {
        let sqlStr = 'SELECT * FROM word_compare WHERE text_1 = ? AND text_2 = ?';
        db.query(sqlStr, [word1, word2], (error, results) => {
            if (error) {
                rejects(-1);
            }
            if (results.length == 0) {
                resolve(-1);
            }
            if (results.length > 0) {
                resolve(results[0].score);
            }
        });
    });
}
async function setWord(word1, word2, score) {
    return new Promise((resolve, rejects) => {
        let sqlStr = 'INSERT INTO word_compare (id, text_1, text_2, score) VALUES (NULL, ?, ?, ?);';
        db.query(sqlStr, [word1, word2, score], (error, results) => {
            if (error) {
                return resolve(false);
            }
            if (results.affectedRows == 1) {
                return resolve(true);
            }
        });
    });
}
